scripts.content:
extends Node

signal save_completed(slot: int)
signal load_completed(slot: int)
signal autosave_triggered

const SAVE_VERSION := 1
const SAVE_DIR := "{{save_directory}}"
const MAX_SLOTS := {{max_save_slots}}
const AUTO_SAVE_INTERVAL := {{auto_save_interval}}

var _auto_save_timer: float = 0.0

func _ready():
	DirAccess.make_dir_recursive_absolute(SAVE_DIR)

func _process(delta):
	if AUTO_SAVE_INTERVAL > 0:
		_auto_save_timer += delta
		if _auto_save_timer >= AUTO_SAVE_INTERVAL:
			_auto_save_timer = 0.0
			autosave_triggered.emit()
			save_game(0)

func save_game(slot: int) -> bool:
	if slot < 0 or slot >= MAX_SLOTS:
		push_error("Save slot %d out of range [0, %d]" % [slot, MAX_SLOTS - 1])
		return false

	var save_data := {
		"version": SAVE_VERSION,
		"timestamp": Time.get_unix_time_from_system(),
		"scene_path": get_tree().current_scene.scene_file_path,
		"player_data": _collect_player_data(),
		"world_state": _collect_world_state(),
	}

	var file := FileAccess.open("%s/save_%d.json" % [SAVE_DIR, slot], FileAccess.WRITE)
	if file == null:
		push_error("Failed to open save file for slot %d" % slot)
		return false

	file.store_string(JSON.stringify(save_data, "\t"))
	file.close()
	save_completed.emit(slot)
	return true

func load_game(slot: int) -> Dictionary:
	if slot < 0 or slot >= MAX_SLOTS:
		push_error("Load slot %d out of range [0, %d]" % [slot, MAX_SLOTS - 1])
		return {}

	var path := "%s/save_%d.json" % [SAVE_DIR, slot]
	if not FileAccess.file_exists(path):
		push_warning("No save file for slot %d" % slot)
		return {}

	var file := FileAccess.open(path, FileAccess.READ)
	var json := JSON.new()
	var error := json.parse(file.get_as_text())
	file.close()

	if error != OK:
		push_error("Failed to parse save file for slot %d" % slot)
		return {}

	var data: Dictionary = json.get_data()
	load_completed.emit(slot)
	return data

func get_save_info(slot: int) -> Dictionary:
	var path := "%s/save_%d.json" % [SAVE_DIR, slot]
	if not FileAccess.file_exists(path):
		return {}
	var file := FileAccess.open(path, FileAccess.READ)
	var json := JSON.new()
	json.parse(file.get_as_text())
	file.close()
	var data: Dictionary = json.get_data()
	return {"slot": slot, "timestamp": data.get("timestamp", 0), "scene": data.get("scene_path", "")}

func _collect_player_data() -> Dictionary:
	var player = get_tree().get_first_node_in_group("player")
	if player:
		return {"position": {"x": player.global_position.x, "y": player.global_position.y, "z": player.global_position.z}}
	return {}

func _collect_world_state() -> Dictionary:
	return {}
